// src/components/BookPage.jsx

export default function BookPage({
  page,
  pageNum,
  total,
  onShowRef,
  pageW,
  pageH,
}) {
  const isCover = page.type === "cover";
  const isEnd = page.type === "end";

  const scale = Math.min(pageW / 380, pageH / 500, 1.6);
  const em = (base) => Math.round(base * scale);

  return (
    <div
      style={{
        width: "100%",
        height: "100%",
        background: page.bg || "#fff",
        color: page.textColor || "#333",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        padding: `${em(24)}px ${em(20)}px`,
        boxSizing: "border-box",
        fontFamily: "'Bubblegum Sans', cursive",
        position: "relative",
        overflowY: "auto",
        overflowX: "hidden",
        userSelect: "none",
      }}
    >
      {/* Decorative circles */}
      <div
        style={{
          position: "absolute",
          top: em(-45),
          left: em(-45),
          width: em(140),
          height: em(140),
          borderRadius: "50%",
          background: "rgba(255,255,255,0.13)",
          pointerEvents: "none",
        }}
      />

      <div
        style={{
          position: "absolute",
          bottom: em(-30),
          right: em(-30),
          width: em(100),
          height: em(100),
          borderRadius: "50%",
          background: "rgba(255,255,255,0.10)",
          pointerEvents: "none",
        }}
      />

      {/* Learn Button */}
      {page.reference && (
        <button
          onClick={() => onShowRef?.(page.reference)}
          style={{
            position: "absolute",
            top: em(10),
            left: em(10),
            background: "rgba(255,255,255,0.28)",
            border: "1px solid rgba(255,255,255,0.55)",
            borderRadius: em(20),
            padding: `${em(4)}px ${em(10)}px`,
            cursor: "pointer",
            fontSize: em(12),
            fontWeight: 700,
            color: page.textColor || "#333",
            backdropFilter: "blur(4px)",
            boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
          }}
        >
          🔍 Learn
        </button>
      )}

      {/* Stars */}
      {(isCover || isEnd) && (
        <div
          style={{
            position: "absolute",
            top: em(10),
            right: em(10),
            fontSize: em(22),
            opacity: 0.75,
            letterSpacing: em(4),
          }}
        >
          ⭐🌟⭐
        </div>
      )}

      {/* Image */}
      {page.image && (
        <img
          src={page.image}
          alt={page.title}
          style={{
            width: em(isCover || isEnd ? 180 : 140),
            maxWidth: "80%",
            height: "auto",
            marginBottom: em(12),
            objectFit: "contain",
            filter: "drop-shadow(0 4px 12px rgba(0,0,0,0.15))",
          }}
        />
      )}

      {/* Emoji fallback */}
      {!page.image && (
        <div
          style={{
            fontSize: em(isCover || isEnd ? 88 : 68),
            lineHeight: 1,
            marginBottom: em(10),
          }}
        >
          {page.emoji || "📖"}
        </div>
      )}

      {/* Title */}
      <div
        style={{
          fontSize: em(
            page.titleSize ||
              (isCover || isEnd ? page.fontSize || 32 : 24)
          ),
          fontWeight: 800,
          textAlign: "center",
          lineHeight: 1.2,
          marginBottom: em(8),
          textShadow: "0 2px 10px rgba(0,0,0,0.18)",
          letterSpacing: isCover ? "0.04em" : "0.01em",
        }}
      >
        {page.title}
      </div>

      {/* Subtitle */}
      {page.subtitle && (
        <div
          style={{
            fontSize: em(17),
            opacity: 0.92,
            textAlign: "center",
            marginBottom: em(14),
            fontStyle: "italic",
          }}
        >
          {page.subtitle}
        </div>
      )}

      {/* Main Text */}
      {page.text && (
        <div
          style={{
            fontSize: em(page.fontSize || 17),
            textAlign: "center",
            lineHeight: 1.75,
            maxWidth: em(320),
            marginTop: em(8),
            background: "rgba(255,255,255,0.28)",
            borderRadius: em(18),
            padding: `${em(14)}px ${em(18)}px`,
            backdropFilter: "blur(4px)",
          }}
        >
          {page.text}
        </div>
      )}

      {/* Facts Section */}
      {page.reference?.facts?.length > 0 && (
        <div
          style={{
            marginTop: em(18),
            background: "rgba(255,255,255,0.25)",
            borderRadius: em(14),
            padding: em(14),
            width: "90%",
            maxWidth: em(330),
            backdropFilter: "blur(4px)",
          }}
        >
          <h3
            style={{
              margin: `0 0 ${em(10)}px 0`,
              textAlign: "center",
              fontSize: em(16),
            }}
          >
            📚 Did You Know?
          </h3>

          <ul
            style={{
              margin: 0,
              paddingLeft: em(18),
              fontSize: em(13),
              lineHeight: 1.6,
            }}
          >
            {page.reference.facts.map((fact, index) => (
              <li key={index} style={{ marginBottom: em(6) }}>
                {fact}
              </li>
            ))}
          </ul>

          {page.reference.learnMore && (
            <div
              style={{
                marginTop: em(10),
                textAlign: "center",
              }}
            >
              <a
                href={page.reference.learnMore}
                target="_blank"
                rel="noreferrer"
                style={{
                  color: page.textColor || "#333",
                  fontWeight: "bold",
                  textDecoration: "underline",
                }}
              >
                Learn More →
              </a>
            </div>
          )}
        </div>
      )}

      {/* Bottom Emoji */}
      {page.emoji && (
        <div
          style={{
            fontSize: em(42),
            marginTop: em(16),
          }}
        >
          {page.emoji}
        </div>
      )}

      {/* Page Number */}
      {!isCover && (
        <div
          style={{
            position: "absolute",
            bottom: em(10),
            fontSize: em(12),
            opacity: 0.55,
            fontFamily: "'Nunito', sans-serif",
          }}
        >
          {pageNum} / {total}
        </div>
      )}
    </div>
  );
}
